                                <div class=\"form-group\">
                                    <div class=\"form-line\">
                                        <select id=\"facfac\" name=\"facfac\" class=\"form-control\">
                                            <option value=\"\" disabled selected>Faites votre choix</option>
                                            {% for fac in chantier.factures %}
                                                {% if fac.etat == \"save\" %}
                                                    {% if fac.type == \"devis\" %}
                                                        <option value=\"{{ fac.id }}\" class=\"{{ fac.id }}\">FACTURE
                                                            Nº{{ fac.numfacture }} | Devis
                                                            N°{{ fac.devis.iddevis }} </option>
                                                    {% endif %}
                                                    {% if fac.type == \"decompte\" %}
                                                        <option value=\"{{ fac.id }}\" class=\"{{ fac.id }}\">FACTURE
                                                            Nº{{ fac.numfacture }} | Devis
                                                            N°{{ fac.decompte.devis.iddevis }} </option>
                                                    {% endif %}
                                                    {% if fac.type == \"acompte\" %}
                                                        <option value=\"{{ fac.id }}\" class=\"{{ fac.id }}\">FACTURE
                                                            Nº{{ fac.numfacture }} | Devis
                                                            N°{{ fac.acompte.devis.iddevis }} </option>
                                                    {% endif %}
                                                     {% if fac.type == \"retenue\" %}
                                                        <option value=\"{{ fac.id }}\" class=\"{{ fac.id }}\">FACTURE
                                                            Nº{{ fac.numfacture }} | Devis
                                                            N°{{ fac.acompte.devis.iddevis }} </option>
                                                    {% endif %}
                                                {% endif %}
                                            {% endfor %}
                                        </select>
                                    </div>
                                    <p class=\"h6 dvfac\"></p>
                                    <p class=\"h6 dvface\"></p>
                                    <p class=\"h6 dvfaces\"></p>
                                    <p class=\"h6 resta hide\"></p>
                                </div>
                            </div>
                        </div>
