    <div class=\"modal fade right\" id=\"modalDeplacerInterve\" tabindex=\"-1\" role=\"dialog\" aria-labelledby=\"myModalLabel\"
         aria-hidden=\"true\">
        <div class=\"modal-dialog modal-full-height modal-right\" role=\"document\">
            <div class=\"modal-content\">
                <div class=\"p-5 bg-pri\">
                    <div class=\"modal-header text-white\">
                        <h4 class=\"modal-title text-white\" id=\"defaultModalLabel\">4- DÉPLACER DES INTERVENANTS</h4>
                    </div>
                </div>
                <div class=\"modal-body m-t-10 bien\">
                    <div class=\"body\">

                        <form id=\"deplacerInterveForm\">
                            <input type=\"hidden\" name=\"token\" value=\"{{ csrf_token('depinterve') }}\"/>
                            <div class=\"row clearfix m-b-10\">
                                <div class=\"col-sm-12\">
                                    <label class=\"form-label m-b--30 col-blue bolo\">INTERVENANTS</label>
                                    <div class=\"form-group\">
                                        <div class=\"form-line\">
                                            <p>Maintenez la touche CTRL enfoncée pour plusieurs sélections.</p>
                                            <select class=\"form-control\" multiple=\"multiple\" name=\"intervenants\">
                                                {% for interve in allinterve %}
                                                    <option value=\"{{ interve.id }}\"
                                                            title=\"{{ interve.nom }}\">{{ interve.nom|length > 40 ? interve.nom|slice(0, 40) ~ '…' : interve.nom }}</option>
                                                {% endfor %}
                                            </select>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div class=\"row clearfix m-b-10\">
                                <div class=\"col-sm-12\">
                                    <label class=\"form-label m-b--30 col-blue bolo\">PROJETS</label>
                                    <div class=\"form-group\">
                                        <div class=\"form-line\">
                                            <select class=\"form-control show-tick\" name=\"nouveauchantier\">
                                                {% for cli in clients %}
                                                    <optgroup label=\"{{ cli.nomclient }}\" class=\" bolo700 col-pink\">
                                                        {% for pro in cli.chantiers %}
                                                            {% if pro.id != chantier.id %}
                                                                {% if pro.corbeille is null and pro.archiver != 'oui' %}
                                                                    <option value=\"{{ pro.id }}\"
                                                                            title=\"{{ pro.nomchantier }}\"
                                                                            class=\"col-blue-grey\"
                                                                            style=\"font-weight: 500 !important; font-size: 15px !important;\">{{ pro.nomchantier|length > 40 ? pro.nomchantier|slice(0, 40)|capitalize ~ '…' : pro.nomchantier|capitalize }}</option>
                                                                {% endif %}
                                                            {% endif %}
                                                        {% endfor %}
                                                    </optgroup>
                                                {% endfor %}
                                            </select>

                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div class=\"text-center\">
                                <input type=\"submit\" id=\"depIntervenant\" value=\"ENREGISTRER\"
                                       class=\"btn btn-link waves-effect text-white bg-teal\">
                                <div type=\"button\" id=\"closedepIntervenant\"
                                     class=\"btn btn-link waves-effect text-white bg-pink\"
                                     data-dismiss=\"modal\">
                                    FERMER
                                </div>
                                <img src=\"{{ asset('img/loading.gif') }}\" style=\"width: 50px; display:none;\"
                                     class=\"align-justify\" id=\"loaddepIntervenant\">
                            </div>
                            <br><br><br>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    </div>
