    <section class=\"content fixed-top\">
        <div class=\"container-fluid\" style=\"margin: 0 14px 0 14px\">
            <div class=\"row\">
                <div class=\"col-md-12\">
                    <div id=\"ressult\" style=\"width: 100%; align-content: start\" class=\"text-left\"></div>
                </div>
            </div>
