    <section class=\"content\" style=\"margin-top: 80px !important;\" id=\"sechantier\">
        <div class=\"container-fluid\">
            <div class=\"block-header\">
                <div class=\"row clearfix p-b-5\">
                    <div class=\"col-xs-12 col-sm-12\">
                        <h2 class=\"text-center\">
                            {% if chantier.etat == \"etude\" %} CHANTIER EN ÉTUDE {% endif %}
                            {% if chantier.etat == \"encours\" %} CHANTIER EN COURS {% endif %}
                            {% if chantier.etat == \"archiver\" %} CHANTIER TERMINÉ {% endif %}
                            {% if chantier.etat == \"cloturer\" %} CHANTIER CLÔTURÉ {% endif %}
                        </h2>
                    </div>
                </div>
                <div class=\"row clearfix m-t-20 p-b-5\" style=\"margin-top: 40px;\">
                    <div class=\"col-xs-12 col-sm-5\" style=\"margin-top: -40px;\">
                        <div class=\"card card-about-me\">
                            <div class=\"profile-header h3 text-white text-center bg-pri\" style=\"padding: 6px\">
                                <h4 class=\"font-bold\">{{ chantier.nomchantier|upper }}</h4>
                                <h4><a href=\"{{ path('client',{'id':client.getId()} ) }}\"
                                       class=\"col-yellow bolo700\">{{ client.nomclient|upper }}</a></h4>
                                <h4 class=\"col-amber bolo600\">AVANCEMENT DU
                                    CHANTIER: {{ chantier.progression|number_format(2,',',' ') }}%<br>
                                    <span style=\"font-size: 14px;\">(Selon les décomptes validés et factures d'acompte )</span>
                                </h4>
                            </div>
                            <div class=\"body\" style=\"margin-top: -20px\">
                                <ul>
                                    <li>
                                        <div class=\"title pri\">
                                            <i class=\"material-icons\">key</i>RÉFÉRENCE CONTRAT
                                        </div>
                                        <div class=\"content col-black\">
                                            {{ chantier.contrat }}
                                        </div>
                                    </li>
                                    <li>
                                        <div class=\"title pri\">
                                            <i class=\"material-icons\">person</i>CHEFS DU CHANTIER
                                        </div>
                                        <div class=\"content\">
                                            {% for super in chantier.superviseurs %}
                                                <p class=\"col-black\"> # {{ super.noms }}</p>
                                            {% endfor %}
                                        </div>
                                    </li>
                                    <li>
                                        <div class=\"title pri\">
                                            <i class=\"material-icons\">notes</i>DESCRIPTION
                                        </div>
                                        <div class=\"content col-black\">
                                            {{ chantier.description|striptags|raw }}
                                        </div>
                                    </li>
                                    <li>
                                        <div class=\"title pri\">
                                            <i class=\"material-icons\">alarm</i>
                                            DÉBUT / FIN
                                        </div>
                                        <div class=\"content col-black\">
                                            {{ chantier.ddebut|date('d/m/Y') }}
                                            / {{ chantier.dfin|date('d/m/Y') }}
                                        </div>
                                    </li>
                                    <li>
                                        <div class=\"title pri\">
                                            <i class=\"material-icons\">location_on</i>
                                            LOCALISATION
                                        </div>
                                        <div class=\"content col-black\">
                                            <p> {{ chantier.localisation|capitalize }}</p>
                                        </div>
                                    </li>
                                    <li>
                                        <div class=\"text-center\">
                                            <button type=\"button\"
                                                    class=\"btn btn-sm bg-green m-b-10 text-white waves-effect\"
                                                    data-toggle=\"modal\" data-target=\"#modalChantier\">
                                                MODIFIER
                                            </button>
                                        </div>
                                    </li>
                                </ul>
                            </div>
                        </div>
                    </div>
                    {% if master.id != 1 %}

                        {% set ccharge = 0 %}
                        {% set ccnocharge = 0 %}
                        {% for caiss in chantier.caisses %}
                            {% if caiss.etat == 'valide' %}
                                {% if caiss.corbeille is null and caiss.type == 3 %}
                                    {% set ccharge = ccharge + caiss.montant %}
                                {% endif %}
                            {% endif %}
                            {% if caiss.etat == 'save' %}
                                {% if caiss.corbeille is null and caiss.type == 3 %}
                                    {% set ccnocharge = ccnocharge + caiss.montant %}
                                {% endif %}
                            {% endif %}
                        {% endfor %}

                        {% set bonpresta = 0 %}
                        {% set bonprestarecu = 0 %}
                        {% set bonfourni = 0 %}
                        {% set bonfournirecu = 0 %}
                        {% for bon in chantier.bons %}
                            {% if bon.fournisseur and bon.devis.corbeille == null %}
                                {% if bon.etat == 'valide' and bon.fournisseur.corbeille == null %}
                                    {% if bon.corbeille is null and bon.type == \"pst\" %}
                                        {% set bonpresta = bonpresta + bon.totalttc %}
                                        {% set bonprestarecu = bonprestarecu + bon.recu %}
                                    {% endif %}
                                    {% if bon.corbeille is null and bon.type == \"oui\" %}
                                        {% set bonfourni = bonfourni + bon.totalttc %}
                                        {% set bonfournirecu = bonfournirecu - bon.recu %}
                                    {% endif %}
                                    {% if bon.corbeille is null and bon.type == \"non\" %}
                                        {% set bonfourni = bon.totalttc + bonfourni %}
                                    {% endif %}
                                {% endif %}
                            {% endif %}
                        {% endfor %}
                        <div class=\"col-xs-12 col-sm-7\" style=\"margin-top: -20px;\">
                            <div class=\"row clearfix\" style=\"margin-bottom: 50px\">
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\" style=\"height: 120px; margin-bottom: 50px\">
                                    <table class=\"table-bordered\" style=\"width: 100%;\">
                                        {% if chantier.etat != \"etude\" %} <tr><td class=\"bg-blue\">DEVIS VALIDÉS</td></tr>{% endif %}
                                        {% if chantier.etat == \"etude\" %} <tr><td class=\"bg-blue\">DEVIS NON VALIDÉS</td></tr>{% endif %}
                                        <tr><td><span class=\"col-black bolo700\">Total:</span><br>{{ chantier.cout|number_format(2,',',' ') }}</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Réglé:</span><br>{{ chantier.reglement|number_format(2,',',' ') }}</td></tr>
                                        <tr><td class=\"bg-white\"><span class=\"col-pink bolo700\">Solde:</span><br><span class=\"col-black bolo700\">{{ (chantier.cout|number_format(2,'.','') -  chantier.reglement|number_format(2,'.',''))|number_format(2,',',' ') }}</span></td></tr>
                                    </table>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\" style=\"height: 120px; margin-bottom: 50px\">
                                    <table class=\"table-bordered\" style=\"width: 100%; \">
                                        <tr><td class=\"bg-blue\">BONS FOURNISSEURS</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Total:</span><br>{{ chantier.bonfournisseurs|number_format(2,',',' ') }}</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Réglé:</span><br>{{ chantier.paiefournisseurs|number_format(2,',',' ') }}</td></tr>
                                        <tr><td class=\"bg-white\"><span class=\"col-pink bolo700\">Reste à régler:</span><br><span class=\"col-black bolo700\">{{ (chantier.bonfournisseurs - chantier.paiefournisseurs)|number_format(2,',',' ') }}</span></td></tr>
                                    </table>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\" style=\"height: 120px; margin-bottom: 50px\">
                                    <table class=\"table-bordered\" style=\"width: 100%;\">
                                        <tr><td class=\"bg-blue\">BONS PRESTATAIRES</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Total:</span><br>{{ chantier.bonprestataires|number_format(2,',',' ') }}</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Réglé:</span><br>{{ chantier.paieprestataires|number_format(2,',',' ') }}</td></tr>
                                        <tr><td class=\"bg-white\"><span class=\"col-pink bolo700\">Reste à régler:</span><br><span class=\"col-black bolo700\">{{ (chantier.bonprestataires - chantier.paieprestataires)|number_format(2,',',' ') }}</span></td></tr>
                                    </table>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\" style=\"height: 120px;\">
                                    <table class=\"table-bordered\" style=\"width: 100%;\">
                                        <tr><td class=\"bg-blue\">CHARGES DIVERSES</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Total:</span><br>{{ chantier.chargechantiers|number_format(2,',',' ') }}</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Réglé:</span><br>{{ chantier.chargepaiechantiers|number_format(2,',',' ') }}</td></tr>
                                        <tr><td class=\"bg-white\"><span class=\"col-pink bolo700\">Reste à régler:</span><br><span class=\"col-black bolo700\">{{ (chantier.chargechantiers - chantier.chargepaiechantiers)|number_format(2,',',' ') }}</span></td></tr>
                                    </table>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\" style=\"height: 120px\">
                                    <table class=\"table-bordered\" style=\"width: 100%;\">
                                        <tr><td class=\"bg-blue\">DÉPENSES TOTALES</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Total:</span><br>{{ (chantier.chargechantiers + chantier.bonfournisseurs + chantier.bonprestataires)|number_format(2,',',' ') }}</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Réglé:</span><br>{{ (ccharge + bonprestarecu + bonfournirecu)|number_format(2,',',' ') }}</td></tr>
                                        <tr><td class=\"bg-white\"><span class=\"col-pink bolo700\">Reste à régler:</span><br><span class=\"col-black bolo700\">{{ ((ccharge + ccnocharge + bonpresta + bonfourni) - (ccharge + bonprestarecu + bonfournirecu))|number_format(2,',',' ') }}</span></td></tr>
                                    </table>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\" style=\"height: 120px;\">
                                    <table class=\"table-bordered\" style=\"width: 100%; \">
                                        <tr><td class=\"bg-blue\">RÉCAP CHANTIER</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Règlements Client:</span><br>{{ chantier.reglement|number_format(2,',',' ') }}</td></tr>
                                        <tr><td><span class=\"col-black bolo700\">Dépenses effectuées:</span><br>{{ (ccharge + bonprestarecu + bonfournirecu)|number_format(2,',',' ') }}</td></tr>
                                        <tr><td class=\"bg-white\"><span class=\"col-pink bolo700\">CAISSE:</span><br><span class=\"col-black bolo700\">{{ (chantier.reglement - (ccharge + bonprestarecu + bonfournirecu))|number_format(2,',',' ') }}</span></td></tr>
                                    </table>
                                </div>
                            </div>

                            <div class=\"row\">
                                <div class=\"col-lg-6 col-md-6 col-sm-6 col-xs-12 demo-button-sizes m-t-5\">
                                    <div class=\"button-demo\">
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 waves-effect text-white\"
                                                data-toggle=\"modal\" data-target=\"#mdModalRegle\"
                                                style=\"width: 100%;padding:10px\">+
                                            RÈGLEMENT
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalBonPrepa\"
                                                style=\"width: 100%;padding:10px\">+ BON DE SUIVI DE COMMANDE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalDevis\"
                                                style=\"width: 100%;padding:10px\">+ DEVIS
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalFacture\"
                                                style=\"width: 100%;padding:10px\">+
                                            FACTURE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri  align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalFournisseur\"
                                                style=\"width: 100%;padding:10px\">+ FOURNISSEURS D'ARTICLES
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalBon\"
                                                style=\"width: 100%;padding:10px\">+ BON FOURNISSEUR
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalCaisse\"
                                                style=\"width: 100%;padding:10px\">+ PAIEMENT FOURNISSEURS
                                        </button>
                                    </div>
                                </div>
                                <div class=\"col-lg-6 col-md-6 col-sm-6 col-xs-12 demo-button-sizes m-t-5\">
                                    <div class=\"button-demo\">
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalRecap\"
                                                style=\"width: 100%;padding:10px\">
                                            + GESTION DE STOCKS
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 waves-effect text-white\"
                                                style=\"width: 100%;padding:10px\" data-toggle=\"modal\"
                                                data-target=\"#modalBonLivre\">+ BON DE LIVRAISON
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue  align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalDecompte\"
                                                style=\"width: 100%;padding:10px\">+ DÉCOMPTE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue align-left m-b-10 waves-effect text-white\"
                                                data-toggle=\"modal\" data-target=\"#modalCaisseInterne\"
                                                style=\"width: 100%;padding:10px\">+ CHARGE DIVERSE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalPrestataire\"
                                                style=\"width: 100%;padding:10px\">+ PRESTATAIRES DE SERVICE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalBonPrestataire\"
                                                style=\"width: 100%;padding:10px\">+ BON PRESTATAIRE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalCaissePresta\"
                                                style=\"width: 100%;padding:10px\">+ PAIEMENT PRESTATAIRES
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    {% endif %}

                    {% if master.id == 1 %}

                        {% set ccharge = 0 %}
                        {% set ccnocharge = 0 %}
                        {% for caiss in chantier.caisses %}
                            {% if caiss.etat == 'valide' %}
                                {% if caiss.corbeille is null and caiss.type == 3 %}
                                    {% set ccharge = ccharge + caiss.montant %}
                                {% endif %}
                            {% endif %}
                            {% if caiss.etat == 'save' %}
                                {% if caiss.corbeille is null and caiss.type == 3 %}
                                    {% set ccnocharge = ccnocharge + caiss.montant %}
                                {% endif %}
                            {% endif %}
                        {% endfor %}

                        {% set bonpresta = 0 %}
                        {% set bonfourni = 0 %}
                        {% for bon in chantier.bons %}
                            {% if bon.fournisseur and bon.devis.corbeille == null %}
                                {% if bon.etat == 'valide' and bon.fournisseur.corbeille == null %}
                                    {% if bon.corbeille is null and bon.type == \"pst\" %}
                                        {% set bonpresta = bonpresta + bon.totalttc %}
                                    {% endif %}
                                    {% if bon.corbeille is null and bon.type == \"oui\" %}
                                        {% set bonfourni = bonfourni + bon.totalttc %}
                                    {% endif %}
                                    {% if bon.corbeille is null and bon.type == \"non\" %}
                                        {% set bonfourni = bonfourni - bon.totalttc %}
                                    {% endif %}
                                {% endif %}
                            {% endif %}
                        {% endfor %}
                        <div class=\"col-xs-12 col-sm-7\" style=\"margin-top: -20px;\">
                            <div class=\"row clearfix\">
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-light-blue hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold\" style=\"font-size: 14px\">
                                                DEVIS VALIDÉS
                                                <br>{{ chantier.cout|number_format(2,',',' ') }}</div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"125\" data-speed=\"15\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-pink hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold\" style=\"font-size: 14px\">
                                                BONS FOURNISSEURS<br>{{ bonfourni|number_format(2,',',' ') }}</div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"257\" data-speed=\"1000\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-green hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold\" style=\"font-size: 14px; color:white\">
                                                BONS PRESTATAIRES
                                                <br>{{ bonpresta|number_format(2,',',' ') }}</div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"125\" data-speed=\"15\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-light-green hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\"font-weight-bold\" style=\"font-size: 14px\">
                                                RÈGLEMENT<br>{{ chantier.reglement|number_format(2,',',' ') }}</div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"125\" data-speed=\"15\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-cyan hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold\" style=\"font-size: 14px\">
                                                RESTE À
                                                PAYER<br>{{ (chantier.cout|number_format(2,'.','') -  chantier.reglement|number_format(2,'.',''))|number_format(2,',',' ') }}
                                            </div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"257\" data-speed=\"1000\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12 \">
                                    <div class=\"info-box bg-deep-orange hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold\" style=\"font-size: 14px\">
                                                BALANCE<br>{{ (chantier.reglement - chantier.depense)|number_format(2,',',' ') }}
                                            </div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"257\" data-speed=\"1000\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-pri col-white hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold\" style=\"font-size: 14px\">
                                                TOTAL DÉBOURS<br>{{ (chantier.depense + ccharge)|number_format(2,',',' ') }}
                                            </div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"257\" data-speed=\"1000\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-purple hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold \" style=\"font-size: 14px;\">
                                                CHARGES DIVERSES
                                                <br>{{ ccharge|number_format(2,',',' ') }}</div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"125\" data-speed=\"15\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                                <div class=\"col-lg-4 col-md-4 col-sm-6 col-xs-12\">
                                    <div class=\"info-box bg-amber hover-expand-effect\">
                                        <div class=\"content\">
                                            <div class=\" font-weight-bold \" style=\"font-size: 14px;\">
                                                MARGE ACTUELLE
                                                <br>{{ (chantier.cout - depcaisse)|number_format(2,',',' ') }}</div>
                                            <div class=\"number count-to\" data-from=\"0\" data-to=\"125\" data-speed=\"15\"
                                                 data-fresh-interval=\"20\"></div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class=\"row\">
                                <div class=\"col-lg-6 col-md-6 col-sm-6 col-xs-12 demo-button-sizes m-t-5\">
                                    <div class=\"button-demo\">
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 waves-effect text-white\"
                                                data-toggle=\"modal\" data-target=\"#mdModalRegle\"
                                                style=\"width: 100%;padding:10px\">+
                                            RÈGLEMENT
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalRecap\"
                                                style=\"width: 100%;padding:10px\">
                                            + GESTION DE STOCKS
                                        </button>

                                        <button type=\"button\"
                                                class=\"btn bg-blue align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalDevis\"
                                                style=\"width: 100%;padding:10px\">+ DEVIS
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalFacture\"
                                                style=\"width: 100%;padding:10px\">+
                                            FACTURE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri  align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalFournisseur\"
                                                style=\"width: 100%;padding:10px\">+ FOURNISSEURS D'ARTICLES
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#mdModalBon\"
                                                style=\"width: 100%;padding:10px\">+ BON DE COMMANDE FOURNISSEUR
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalCaisse\"
                                                style=\"width: 100%;padding:10px\">+ PAIEMENT FOURNISSEUR
                                        </button>
                                    </div>
                                </div>
                                <div class=\"col-lg-6 col-md-6 col-sm-6 col-xs-12 demo-button-sizes m-t-5\">
                                    <div class=\"button-demo\">
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalBonPrepa\"
                                                style=\"width: 100%;padding:10px\">+ BON DE SUIVI DE COMMANDE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-teal align-left m-b-10 waves-effect text-white\"
                                                style=\"width: 100%;padding:10px\" data-toggle=\"modal\"
                                                data-target=\"#modalBonLivre\">+ BON DE LIVRAISON
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue  align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalDecompte\"
                                                style=\"width: 100%;padding:10px\">+ DÉCOMPTE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-blue align-left m-b-10 waves-effect text-white\"
                                                data-toggle=\"modal\" data-target=\"#modalCaisseInterne\"
                                                style=\"width: 100%;padding:10px\">+ CHARGE DIVERSE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalPrestataire\"
                                                style=\"width: 100%;padding:10px\">+ PRESTATAIRES DE SERVICE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalBonPrestataire\"
                                                style=\"width: 100%;padding:10px\">+ BON DE COMMANDE PRESTATAIRE
                                        </button>
                                        <button type=\"button\"
                                                class=\"btn bg-pri align-left m-b-10 text-white waves-effect\"
                                                data-toggle=\"modal\" data-target=\"#modalCaissePresta\"
                                                style=\"width: 100%;padding:10px\">+ PAIEMENT PRESTATAIRE
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    {% endif %}

                </div>
                <div class=\"row clearfix m-t-30 \">
                    <div class=\"col-xs-12 col-sm-12\">
                        <div class=\"panel-group\" id=\"accordion_1\" role=\"tablist\" aria-multiselectable=\"true\">

                            {# RELEVE #}
                            <div class=\"panel panel-primary\">
                                <div class=\"panel-heading bg-pri\" role=\"tab\" id=\"headingOne_1\">
                                    <h5 class=\"panel-title\">
                                        <a class=\"collapsed outai text-white\" role=\"button\" data-toggle=\"collapse\"
                                           data-parent=\"#accordion_1\"
                                           href=\"#collapseOne_1\" aria-expanded=\"false\"
                                           aria-controls=\"collapseOne_1\">
                                            1- Relevé du chantier
                                        </a>
                                    </h5>
                                </div>
                                <div id=\"collapseOne_1\" class=\"panel-collapse collapse\" role=\"tabpanel\"
                                     aria-labelledby=\"headingOne_1\">
                                    <div class=\"panel-body\" style=\"overflow: scroll\">
                                        <div class=\"table-responsive shadow\" style=\"padding: 10px\">

                                                    <span id=\"chantiervale\"
                                                          style=\"visibility: hidden\">{{ chantier.id }}</span>
                                            <table class=\"table-striped table-bordered display nowrape\"
                                                   style=\"width: 100%\"
                                                   id=\"dataRELE\">
                                                <thead>
                                                <tr style=\"color: dimgray !important;\">
                                                    <th>DATE</th>
                                                    <th>OPÉRATION</th>
                                                    <th>SORTIE DE CAISSE</th>
                                                    <th>ENTRÉE DE CAISSE</th>
                                                    <th>VALIDÉ PAR</th>
                                                </tr>
                                                </thead>
                                                <tbody>
                                                {% for don in valider %}
                                                    {% if don.type !=  2 %}
                                                        <tr>
                                                            <td>{{ don.date|date('Y.m.d') }}</td>
                                                            {% if don.type ==  1 %}
                                                                <td title=\"{{ don.operation }}\">
                                                                    <a href=\"{{ path('editcaisse',{'idcaisse':don.idlink, 'idchantier':chantier.id}) }}\"
                                                                       class=\"col-black\">
                                                                        CAISSE N°:
                                                                        {{ don.operation|length > 60 ? don.operation|slice(0, 60)|upper ~ '…' :
                                                                        don.operation|upper }}
                                                                    </a>
                                                                </td>
                                                            {% endif %}
                                                            {% if don.type ==  3 %}
                                                                <td title=\"{{ don.operation }}\">
                                                                    <a href=\"{{ path('editbon', {'id': don.idlink, 'idchantier': chantier.id}) }}\"
                                                                       class=\"col-pink\">
                                                                        {{ don.operation|length > 60 ? don.operation|slice(0, 60)|upper ~ '…' :
                                                                        don.operation|upper }}
                                                                    </a>
                                                                </td>
                                                            {% endif %}
                                                            <td class=\"text-right\">{{ don.debit|number_format(2,',',' ') }}</td>
                                                            <td class=\"text-right\"> {{ don.credit|number_format(2,',',' ') }}</td>
                                                            <td class=\"text-left col-blue\">
                                                                {% if don.dobyuser  is not null %}
                                                                    <i
                                                                            class=\"fa fa-user col-blue\"></i>&nbsp;{{ don.dobyuser.nom|upper }}
                                                                    &nbsp;{{ don.dobyuser.prenoms|upper }}
                                                                {% endif %}
                                                            </td>
                                                        </tr>
                                                    {% endif %}
                                                {% endfor %}
                                                </tbody>
                                                <tfoot>
                                                <tr>
                                                    <td></td>
                                                    <td></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td class=\"text-left col-blue\"></td>
                                                </tr>
                                                </tfoot>
                                            </table>
                                            <br>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            {# FIN RELEVE #}


                            {# DEVIS #}
                            <div class=\"panel panel-primary\">
                                <div class=\"panel-heading bg-pri\" role=\"tab\" id=\"headingCin\">
                                    <h5 class=\"panel-title\">
                                        <a class=\"collapsed outai text-white\" role=\"button\" data-toggle=\"collapse\"
                                           data-parent=\"#accordion_1\"
                                           href=\"#collapseCin\" aria-expanded=\"false\"
                                           aria-controls=\"collapseCin\">
                                            2- Devis
                                        </a>
                                    </h5>
                                </div>
                                <div id=\"collapseCin\" class=\"panel-collapse collapse\" role=\"tabpanel\"
                                     aria-labelledby=\"headingCin\">
                                    <div class=\"panel-body \" style=\"overflow: scroll; background-color: #dbdfef\">
                                        <div class=\"table-responsive shadow bg-white\"
                                             style=\"padding: 10px 10px 50px 10px;color:#555; overflow: scroll\">
                                            <h4 class=\"bolo700\">DEVIS VALIDÉS</h4>
                                            <table class=\"table-striped table-bordered display nowrape\"
                                                   style=\"width: 100%\"
                                                   id=\"dataDEVIS\">
                                                <thead>
                                                <tr class=\"text-center bolderr\">
                                                    <th class=\"mw30\"></th>
                                                    <th class=\"mw30\"></th>
                                                    <th class=\"mw30\"></th>
                                                    <th>DATE</th>
                                                    <th>N° DEVIS</th>
                                                    <th>TOTAL HT</th>
                                                    <th>TOTAL TTC</th>
                                                    <th>RÉGLÉ(TTC)</th>
                                                    <th>SOLDE(TTC)</th>
                                                    <th>RÉFÉRENCE</th>
                                                    <th>ETAT</th>
                                                    <th>CREÉ PAR</th>
                                                </tr>
                                                </thead>
                                                <tbody>
                                                {% set vdth = 0 %}
                                                {% set vdttc = 0 %}
                                                {% set ndth = 0 %}
                                                {% set ndttc = 0 %}

                                                {% for devis in chantier.devis %}
                                                    {% if devis.type is null %}
                                                        {% if devis.etat == 'valide' and devis.corbeille is null %}
                                                            {% set vdth = devis.totalht + vdth %}
                                                            {% set vdttc = devis.totalttc + vdttc %}
                                                        {% endif %}
                                                        {% if devis.etat == 'save' and devis.corbeille is null %}
                                                            {% set ndth = devis.totalht + ndth %}
                                                            {% set ndttc = devis.totalttc + ndttc %}
                                                        {% endif %}
                                                        {% if devis.etat == 'valide' %}
                                                            {% if devis.corbeille is null %}
                                                                {% set regler = 0 %}
                                                                {% for rele  in devis.relevers %}
                                                                    {% if rele.type == 3 %}
                                                                        {% set regler = regler + rele.montant %}
                                                                    {% endif %}
                                                                {% endfor %}
                                                                <tr>
                                                                    <td class=\"text-center\"><input type=\"checkbox\"
                                                                                                   data-toggle=\"toggle\"
                                                                                                   class=\"DEVYS\"
                                                                                                   value=\"{{ devis.id }}\">
                                                                    </td>
                                                                    <td class=\"text-center\">
                                                                        <a href=\"#\"
                                                                           onclick=\"shasha({{ devis.id }},'imprimdevis');\"><i
                                                                                    class=\"fa fa-eye col-green\"
                                                                                    aria-hidden=\"true\"></i></a></td>

                                                                    <td class=\"text-center\"><a href=\"#\"
                                                                                               onclick=\"shushu({{ devis.id }},'shushu');\"
                                                                                               title=\"Opérations liées\"><i
                                                                                    class=\"fa fa-plug col-pink bolo700\"
                                                                                    aria-hidden=\"true\"></i></a></td>
                                                                    <td>{{ devis.date|date('Y-m-d') }}</td>
                                                                    <td>
                                                                        <a href=\"{{ path('editdevis',{'id':devis.id ,'idchantier':devis.chantier.id}) }}\"
                                                                           style=\"color:dodgerblue\">
                                                                       <span class=\"badge badge-pill badge-primary\"
                                                                             title=\"Validé par {% if devis.vabyuser is not null %}{{ devis.vabyuser.prenoms|upper }}{% endif %}\">V</span>
                                                                            DEVIS N° {{ devis.iddevis }}</a>
                                                                    </td>
                                                                    <td class=\"text-right\">{{ devis.totalht|number_format(2,',',' ') }}</td>
                                                                    <td class=\"text-right\">{{ devis.totalttc|number_format(2,',',' ') }}</td>
                                                                    <td class=\"text-right\">{{ regler|number_format(2,',',' ') }}</td>
                                                                    <td class=\"text-right\">{{ (devis.totalttc - regler)|number_format(2,',',' ') }}</td>
                                                                    <td class=\"col-deep-orange\"
                                                                        title=\"{{ devis.devreference|striptags|raw }}\">
                                                                        {{ devis.devreference|striptags|raw }}
                                                                    </td>
                                                                    <td>DEVIS VALIDÉS</td>

                                                                    <td class=\"text-left col-blue bolo600\"><i
                                                                                class=\"fa fa-user col-blue bolo600\"></i>&nbsp;
                                                                        {% if devis.dobyuser is not null %}
                                                                            {{ devis.dobyuser.nom|upper }}
                                                                            &nbsp;{{ devis.dobyuser.prenoms|upper }}
                                                                        {% endif %}
                                                                    </td>
                                                                </tr>
                                                            {% endif %}
                                                        {% endif %}
                                                    {% endif %}
                                                {% endfor %}
                                                </tbody>
                                                <tfoot>
                                                <tr>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                </tr>
                                                </tfoot>
                                            </table>
                                        </div>
                                        <div class=\"table-responsive shadow bg-white\"
                                             style=\"padding: 10px 10px 50px 10px; margin-top: 30px; color:#555; overflow: scroll\">
                                            <h4 class=\"bolo700\">DEVIS NON VALIDÉS</h4>
                                            <table class=\"table-striped table-bordered display nowrap\"
                                                   style=\"width: 100%\"
                                                   id=\"dataDEVIS2\">
                                                <thead>
                                                <tr class=\"text-center bolderr\">
                                                    <th class=\"mw30\"></th>
                                                    <th class=\"mw30\"></th>
                                                    <th>DATE</th>
                                                    <th>N° DEVIS</th>
                                                    <th>TOTAL HT</th>
                                                    <th>TOTAL TTC</th>
                                                    <th>RÉFÉRENCE</th>
                                                    <th>ETAT</th>
                                                    <th>CREÉ PAR</th>
                                                </tr>
                                                </thead>
                                                <tbody>
                                                {% for devis in chantier.devis %}
                                                    {% if devis.etat == 'save' %}
                                                        {% if devis.corbeille is null and devis.type is null %}
                                                            <tr>
                                                                <td class=\"text-center\">
                                                                    <input type=\"checkbox\" data-toggle=\"toggle\"
                                                                           class=\"DEVYS2\"
                                                                           value=\"{{ devis.id }}\"></td>
                                                                <td class=\"text-center\"><a href=\"#\"
                                                                                           onclick=\"shasha({{ devis.id }},'imprimdevis');\"><i
                                                                                class=\"fa fa-eye col-green\"
                                                                                aria-hidden=\"true\"></i></a></td>
                                                                <td>{{ devis.date|date('Y-m-d') }}</td>
                                                                <td>
                                                                    <a href=\"{{ path('editdevis',{'id':devis.id ,'idchantier':devis.chantier.id}) }}\"
                                                                       style=\"color:dodgerblue\">
                                                                        <span class=\"badge badge-pill badge-blue-grey\"
                                                                              title=\"Dévalidé par {% if devis.vabyuser is not null %}{{ devis.vabyuser.prenoms|upper }}{% endif %}\">V</span>
                                                                        DEVIS
                                                                        N° {{ devis.iddevis }}
                                                                    </a>
                                                                </td>
                                                                <td class=\"text-right\">{{ devis.totalht|number_format(2,',',' ') }}</td>
                                                                <td class=\"text-right\">{{ devis.totalttc|number_format(2,',',' ') }}</td>
                                                                <td class=\"col-deep-orange\"
                                                                    title=\"{{ devis.devreference|striptags|raw }}\">
                                                                    {{ devis.devreference|striptags|raw }}
                                                                </td>
                                                                <td>DEVIS NON VALIDÉS</td>
                                                                <td class=\"text-left col-blue bolo600\"><i
                                                                            class=\"fa fa-user col-blue bolo600\"></i>&nbsp;
                                                                    {% if devis.dobyuser is not null %}
                                                                        {{ devis.dobyuser.nom|upper }}
                                                                        &nbsp;{{ devis.dobyuser.prenoms|upper }}{% endif %}
                                                                </td>
                                                            </tr>
                                                        {% endif %}
                                                    {% endif %}
                                                {% endfor %}
                                                </tbody>
                                                <tfoot>
                                                <tr>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                    <td></td>
                                                    <td></td>
                                                    <td></td>
                                                </tr>
                                                </tfoot>
                                            </table>
                                        </div>

                                        <table class=\"table-bordered d reduire\" style=\"float: right; margin-top: 20px\">
                                            <tr style=\"background-color: slategrey; color: white\">
                                                <th class=\"text-center\"></th>
                                                <th class=\"text-center\">TOTAL HT</th>
                                                <th class=\"text-center\">TOTAL TTC</th>
                                            </tr>
                                            <tr style=\"background-color: slategrey; color: white\">
                                                <td class=\"text-right\">VALIDÉS</td>
                                                <td class=\"text-right\">{{ vdth|number_format(2, ',', ' ') }}</td>
                                                <td class=\"text-right\">{{ vdttc|number_format(2,',',' ') }}</td>
                                            </tr>
                                            <tr style=\"background-color: indianred; color: white\">
