                                                                                - {% if caisse.bon is not null %}BON N° {{ bon.numbon }}
                                                                                    <span class=\"col-black\">[ BON TTC: {{ bon.totalttc|number_format(2,',',' ') }} ]</span>
                                                                                    <span class=\"col-pink\">[ SOLDE: {{ bon.reste|number_format(2,',',' ') }} ]</span>
                                                                                {% endif %} </td>
                                                                            <td class=\"text-center\">
