                                                                        N° {{ facture.devis.iddevis }}</a>
                                                                {% endif %}
                                                                {% if facture.type == \"decompte\" %}
                                                                    <a href=\"{{ path('editdevis', {'id': facture.decompte.devis.id,'idchantier':facture.chantier.id}) }}\">DEVIS
                                                                        N° {{ facture.decompte.devis.iddevis }}</a>
                                                                {% endif %}
                                                                {% if facture.type == \"acompte\" and facture.acompte is not null %}
                                                                    <a href=\"{{ path('editdevis', {'id': facture.acompte.devis.id,'idchantier':facture.chantier.id}) }}\">DEVIS
                                                                        N° {{ facture.acompte.devis.iddevis }}</a>
                                                                {% endif %}
                                                                {% if facture.type == \"retenue\" and facture.acompte is not null %}
