                                                    {% if bon.corbeille is null %}
                                                        {% set nbth = bon.totalht + nbth %}
                                                        {% set nbttc = bon.totalttc + nbttc %}
                                                    {% endif %}
                                                {% endif %}


                                            {% endif %}
                                        {% endfor %}
