                                                            <input type=\"checkbox\" data-toggle=\"toggle\"
                                                                   class=\"STOCK\"
                                                                   value=\"{{ recap.id }}\"></td>
                                                        <td class=\"col-blue\">{{ recap.article.designation|upper }}</td>
                                                        <td style=\"padding: 2px !important; text-align: right\">{{ recap.quantite }}</td>
                                                        <td style=\"padding: 2px !important; text-align: right\">{{ recap.article.pu|number_format(2, ',', ' ') }}</td>
                                                        <td style=\"padding: 2px !important; text-align: right\">{{ (recap.quantite * recap.article.pu)|number_format(2, ',', ' ') }}</td>
                                                    </tr>
                                                {% endfor %}
                                                {% endif %}
                                                </tbody>
                                            </table>
                                        </div>
                                        <div class=\"table-responsive shadow bg-white\"
                                             style=\"padding: 10px 10px 50px 10px; margin-top: 30px; color:#555; overflow: scroll\">
                                            <table class=\"table-bordered display nowrap\"
                                                   style=\"width: 100%\" id=\"dataRECAP\">
                                                <thead>
                                                <tr>
                                                    <th>ARTICLES | STOCK</th>
                                                    <th>PRÉVISION</th>
                                                    <th>COMMANDÉE</th>
                                                    <th>RESTE</th>
                                                    <th>STOCK RÉEL</th>
                                                </tr>
                                                </thead>
                                                <tbody>
                                                {% if chantier.id != \"897918\" %}
                                                    {% for recap in chantier.recaps %}
                                                        {% set mm = 0 %}
                                                        {% for ligne in invente %}
                                                            {% if ligne.bon.etat == 'valide' and ligne.article == recap.article and ligne.bon.type != \"none\" %}
                                                                {% set mm = ligne.quantite + mm %}
                                                            {% endif %}
                                                        {% endfor %}
                                                        <tr>
                                                            <td style=\"padding: 2px !important;\">{{ recap.article.designation|upper|striptags|raw }}</td>
                                                            <td style=\"padding: 2px !important; text-align: right\">{{ recap.quantite|number_format(2, ',', ' ') }}</td>
                                                            <td style=\"padding: 2px !important; text-align: right\">{{ mm|number_format(2, ',', ' ') }}</td>
                                                            <td style=\"padding: 2px !important; text-align: right\">{{ (recap.quantite - mm) |number_format(2, ',', ' ') }}</td>
                                                            <td style=\"padding: 2px !important; text-align: right\">{{ recap.article.stock|number_format(2, ',', ' ') }}</td>
                                                        </tr>
                                                    {% endfor %}
                                                {% endif %}

                                                </tbody>
                                            </table>
                                        </div>
                                        <div class=\"table-responsive shadow bg-white\"
                                             style=\"padding: 10px 10px 50px 10px; margin-top: 30px; color:#555; overflow: scroll\">
