                                                    <tbody>

                                                    {% for caisse in chantier.caisses %}
                                                        {% if caisse.etat == 'valide' %}
                                                            {% if caisse.corbeille is null and caisse.intervenant is not null %}
                                                                <tr>
                                                                    <td class=\"text-center\">
                                                                        <input type=\"checkbox\" data-toggle=\"toggle\"
                                                                               class=\"CASS\"
                                                                               value=\"{{ caisse.id }}\">
                                                                    </td>
                                                                    <td class=\"text-center\"><a href=\"#\"
                                                                                               onclick=\"shasha({{ caisse.id }},'imprimcaisse');\"><i
                                                                                    class=\"fa fa-eye col-green\"
                                                                                    aria-hidden=\"true\"></i></a></td>
                                                                    <td>{{ caisse.date|date('Y-m-d') }}</td>
                                                                    <td>
                                                                        <a href=\"{{ path('editcaisse',{'idcaisse':caisse.id, 'idchantier':caisse.chantier.id}) }}\"><span
                                                                                    class=\"badge badge-pill badge-primary\"
                                                                                    title=\"Validé par {% if caisse.vabyuser is not null %}{{ caisse.vabyuser.prenoms|upper }}{% endif %}\">V</span>
                                                                            CAISSE N° {{ caisse.numcaisse }}
                                                                        </a></td>
                                                                    <td>
                                                                        {% if caisse.intervenant is not null %}
                                                                            {% if caisse.intervenant.reste <= 0 %}
                                                                                <span class=\"col-pink\">SOLDÉ</span> | {{ caisse.intervenant.nom|upper }}
                                                                                <br>
                                                                            {% else %}
                                                                                <span class=\"col-green\">NON SOLDÉ</span> | {{ caisse.intervenant.nom|upper }}
                                                                                <br>
                                                                            {% endif %}


                                                                            {% if caisse.intervenant.reste <= 0 %}
                                                                                <span class=\"col-black\">
                                                                MONTANT À RECEVOIR : {{ caisse.intervenant.payer|number_format(2,',',' ') }}<br></span>
                                                                                <span>
                                                                            MONTANT RECU : {{ caisse.intervenant.recu|number_format(2,',',' ') }}<br></span>
                                                                                <span>
                                                                <u class=\"text-success\">RESTE À PAYER : {{ caisse.intervenant.reste|number_format(2,',',' ') }}</u><br>
                                                            </span>
                                                                            {% else %}
                                                                                <span class=\"col-black\">
                                                                MONTANT À RECEVOIR : {{ caisse.intervenant.payer|number_format(2,',',' ') }}<br>
                                                                MONTANT RECU : {{ caisse.intervenant.recu|number_format(2,',',' ') }}<br>
                                                                <u class=\"col-pink bolo700\">RESTE À PAYER : {{ caisse.intervenant.reste|number_format(2,',',' ') }}</u><br>
                                                            </span>
                                                                            {% endif %}

                                                                        {% endif %}
                                                                    </td>
                                                                    <td class=\"col-deep-orange\"
                                                                        title=\"{{ caisse.caissereference|striptags|raw }}\">{{ caisse.caissereference|striptags }}</td>
                                                                    <td class=\"text-right\">{{ caisse.montant|number_format(2,',',' ') }}</td>
                                                                    <td class=\"text-left col-blue bolo600\"><i
                                                                                class=\"fa fa-user col-blue\"></i>&nbsp;
                                                                        {% if caisse.dobyuser is not null %}
                                                                            {{ caisse.dobyuser.nom|upper }}
                                                                            &nbsp;{{ caisse.dobyuser.prenoms|upper }} {% endif %}
                                                                    </td>

                                                                    <td> {% if caisse.devis is not null %}DEVIS N°{{ caisse.devis.iddevis }} {% endif %}</td>

                                                                </tr>
                                                            {% endif %}
                                                        {% endif %}
                                                    {% endfor %}

                                                    </tbody>
                                                    <tfoot>
                                                    <tr>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                        <td></td>
                                                        <td></td>
                                                    </tr>
                                                    </tfoot>
                                                </table>
                                            </div>
                                            <div class=\"table-responsive shadow bg-white\"
                                                 style=\"padding: 10px 10px 50px 10px; margin-top: 30px; color:#555; overflow: scroll\">
                                                <table class=\"table-bordered display nowrape\" style=\"width: 100%\"
                                                       id=\"daCAISSE2\">
                                                    <thead>
                                                    <tr class=\"text-center\">
                                                        <th class=\"mw30\"></th>
                                                        <th class=\"mw30\"></th>
                                                        <th>DATE</th>
                                                        <th>N° BON</th>
                                                        <th>ETAT</th>
                                                        <th>FACTURÉ À</th>
                                                        <th>MONTANT</th>
                                                        <th>RÉFÉRENCE</th>
                                                        <th>CREÉ PAR</th>
                                                    </tr>
                                                    </thead>
                                                    <tbody>
                                                    {% for caisse in chantier.caisses %}
                                                        {% if caisse.etat == 'save' %}
                                                            {% if caisse.corbeille is null and caisse.intervenant is not null %}
                                                                <tr>
                                                                    <td class=\"text-center\">
                                                                        <input type=\"checkbox\" data-toggle=\"toggle\"
                                                                               class=\"CASS2\"
                                                                               value=\"{{ caisse.id }}\"></td>
                                                                    <td class=\"text-center\"><a href=\"#\"
                                                                                               onclick=\"shasha({{ caisse.id }},'imprimcaisse');\"><i
                                                                                    class=\"fa fa-eye col-green\"
                                                                                    aria-hidden=\"true\"></i></a></td>
                                                                    <td>{{ caisse.date|date('Y-m-d') }}</td>
                                                                    <td>
                                                                        <a href=\"{{ path('editcaisse',{'idcaisse':caisse.id, 'idchantier':caisse.chantier.id}) }}\"><span
                                                                                    class=\"badge badge-pill bg-blue-grey text-white\"
                                                                                    title=\"Dévalidé par {% if caisse.vabyuser is not null %}{{ caisse.vabyuser.prenoms|upper }}{% endif %}\">V</span>
                                                                            CAISSE N° {{ caisse.numcaisse }}
                                                                        </a>
                                                                    </td>
                                                                    <td>BONS DE CAISSE NON VALIDÉS</td>
                                                                    <td>
                                                                        {% if caisse.intervenant is not null %}
                                                                            {{ caisse.intervenant.nom|length > 30 ? caisse.intervenant.nom|slice(0, 30)|upper ~ '…' :
                                                                            caisse.intervenant.nom|upper }}
                                                                        {% endif %}
                                                                        {% if caisse.fournisseur is not null %}
                                                                            {{ caisse.fournisseur.fournisseur|length > 30 ? caisse.fournisseur.fournisseur|slice(0, 30)|upper ~ '…' :
                                                                            caisse.fournisseur.fournisseur|upper }}
                                                                        {% endif %}
                                                                    </td>
                                                                    <td class=\"text-right\">{{ caisse.montant|number_format(2,',',' ') }}</td>
                                                                    <td class=\"col-deep-orange\"
                                                                        title=\"{{ caisse.caissereference|striptags|raw }}\">
                                                                        {{ caisse.caissereference|striptags|length > 30 ? caisse.caissereference|striptags|slice(0, 30)|capitalize ~ '…' :
                                                                        caisse.caissereference|striptags|capitalize }}
                                                                    </td>

                                                                    <td class=\"text-left col-blue bolo600\"><i
                                                                                class=\"fa fa-user col-blue\"></i>&nbsp; {% if caisse.dobyuser is not null %}{{ caisse.dobyuser.nom|upper }}
                                                                            &nbsp;{{ caisse.dobyuser.prenoms|upper }}  {% endif %}
                                                                    </td>
                                                                </tr>
                                                            {% endif %}
                                                        {% endif %}
                                                    {% endfor %}
                                                    </tbody>
                                                    <tfoot>
                                                    <tr>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td></td>
                                                        <td class=\"text-right bg-blue bolo700 col-white\"></td>
                                                        <td></td>
                                                        <td></td>
                                                    </tr>
                                                    </tfoot>
                                                </table>
                                            </div>
                                            {% set vcth = 0 %}
                                            {% set ncth = 0 %}

                                            {% for caisse in chantier.caisses %}
                                                {% if caisse.corbeille is null and caisse.intervenant is not null %}
                                                    {% if caisse.etat == 'valide' and caisse.fournisseur is null %}
                                                        {% set vcth = caisse.montant + vcth %}
                                                    {% endif %}
                                                    {% if caisse.etat == 'save' and caisse.fournisseur is null %}
                                                        {% set ncth = caisse.montant + ncth %}
                                                    {% endif %}
                                                {% endif %}
                                            {% endfor %}
                                            <table class=\"table-bordered d reduire\"
                                                   style=\"float: right; margin-top: 20px\">
                                                <tr style=\"background-color: slategrey; color: white;\">
                                                    <td colspan=\"2\" class=\"text-right\">
                                                        VALIDÉS
                                                    </td>
                                                    <td class=\"text-right\">{{ vcth|number_format(2,',',' ') }}</td>
                                                </tr>
                                                <tr style=\"background-color: indianred; color: white\">
                                                    <td colspan=\"2\" class=\"text-right\">
                                                        NON VALIDÉS
                                                    </td>
                                                    <td class=\"text-right\">{{ ncth|number_format(2,',',' ') }}</td>
                                                </tr>
                                                <tr class=\"bg-pri text-white\">
                                                    <td colspan=\"2\" class=\"text-right\">
                                                        TOTAUX
                                                    </td>
                                                    <td class=\"text-right\">{{ (ncth+vcth)|number_format(2,',',' ') }}</td>
                                                </tr>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                                {# FIN CAISSES #}

                            {% endif %}
                            {# CAISSES FOURNISSEUR #}

                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>

    <script>
        localStorage.setItem('reloadd', 'chantier/' + document.getElementById('idchantier').value);
    </script>

{% endblock %}
", "content/chantier.html.twig", "C:\\wamp64\\www\\carlinbleu\\templates\\content\\chantier.html.twig");
    }
